    private static void ExtractSettingsRecursive(XmlElement element, Dictionary<string, string> settings, string currentPath)
    {
        // Handle common attribute-based patterns like <setting name="Key" value="Value"/> or <add key="Key" value="Value"/>
        if (element.Name.Equals("setting", StringComparison.OrdinalIgnoreCase) || element.Name.Equals("add", StringComparison.OrdinalIgnoreCase))
